import{_ as t,c as a,o as i,aj as o}from"./chunks/framework.guNMSiFm.js";const p=JSON.parse('{"title":"Fraud Monitoring","description":"","frontmatter":{},"headers":[],"relativePath":"guide/security/fraud-monitoring.md","filePath":"guide/security/fraud-monitoring.md","lastUpdated":1777621302000}'),r={name:"guide/security/fraud-monitoring.md"};function n(s,e,d,l,c,h){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="fraud-monitoring" tabindex="-1">Fraud Monitoring <a class="header-anchor" href="#fraud-monitoring" aria-label="Permalink to &quot;Fraud Monitoring&quot;">​</a></h1><p>Fraud monitoring for an Iroha deployment is an operational control built around ledger events, queries, permissions, and application context. Iroha records what was submitted, accepted, rejected, and committed. Your monitoring system decides which patterns are suspicious for your business process and routes those cases to reviewers or automated response controls.</p><p>Treat fraud monitoring as a separate service rather than logic embedded in a validator. The service should subscribe to ledger activity, enrich it with off-chain risk context, persist evidence, and submit response transactions only through accounts that have explicit permissions.</p><h2 id="monitoring-model" tabindex="-1">Monitoring Model <a class="header-anchor" href="#monitoring-model" aria-label="Permalink to &quot;Monitoring Model&quot;">​</a></h2><p>A useful monitoring pipeline has four stages:</p><ol><li><strong>Collect</strong> ledger and operator signals from Torii event streams, queries, and metrics.</li><li><strong>Enrich</strong> events with off-chain context such as customer status, counterparty lists, application session identifiers, expected limits, and case IDs.</li><li><strong>Detect</strong> suspicious behavior with deterministic rules, reviewer queues, or risk scoring.</li><li><strong>Respond</strong> by alerting operators, pausing application-side workflows, revoking unnecessary permissions, or submitting compensating transactions when your governance process allows it.</li></ol><p>Keep policy decisions outside consensus unless every validator must replay the same decision. Runtime validation should enforce permissions and transaction validity. Fraud monitoring should explain risk, preserve evidence, and help operators act quickly.</p><h2 id="signals-to-collect" tabindex="-1">Signals to Collect <a class="header-anchor" href="#signals-to-collect" aria-label="Permalink to &quot;Signals to Collect&quot;">​</a></h2><p>Start with narrow subscriptions and add broader streams only for investigation:</p><table tabindex="0"><thead><tr><th>Signal</th><th>Source</th><th>Use</th></tr></thead><tbody><tr><td>Transaction status</td><td>Pipeline events</td><td>Detect repeated rejections, failed authorization attempts, and unusual submission patterns</td></tr><tr><td>Account lifecycle and metadata</td><td>Data events and account queries</td><td>Detect new accounts, alias changes, identity updates, and unexpected metadata edits</td></tr><tr><td>Asset balances and transfers</td><td>Asset data events and asset queries</td><td>Detect high-value movement, rapid fan-out, balance drains, and unusual counterparties</td></tr><tr><td>Roles and permissions</td><td>Role and permission queries, role data events</td><td>Detect privilege escalation, emergency grants, and stale high-risk access</td></tr><tr><td>Trigger and contract changes</td><td>Trigger, contract, and executor events</td><td>Detect new automation, changed execution paths, and suspicious upgrade activity</td></tr><tr><td>Configuration and peer changes</td><td>Configuration and peer events</td><td>Detect governance changes that affect validation, networking, or operator visibility</td></tr><tr><td>Operator health</td><td><code>/metrics</code> and Sumeragi status routes</td><td>Separate suspicious user behavior from node overload, queue pressure, or network faults</td></tr></tbody></table><p>Use <a href="/iroha-2-docs/blockchain/filters.html">event filters</a> to avoid processing the entire event stream when a rule only needs accounts, assets, roles, or configuration changes. For periodic reconciliation, combine the stream with paginated <a href="/iroha-2-docs/blockchain/queries.html">queries</a> so the monitor can recover after downtime.</p><h2 id="detection-rules" tabindex="-1">Detection Rules <a class="header-anchor" href="#detection-rules" aria-label="Permalink to &quot;Detection Rules&quot;">​</a></h2><p>Common rule families include:</p><table tabindex="0"><thead><tr><th>Rule family</th><th>Example condition</th><th>Typical response</th></tr></thead><tbody><tr><td>Velocity</td><td>An account transfers more than the expected amount or count within a short window</td><td>Alert reviewers and pause application-side withdrawals for that account</td></tr><tr><td>Fan-out</td><td>Funds move from one account to many newly seen accounts</td><td>Require manual approval before allowing additional transfers</td></tr><tr><td>Balance drain</td><td>A large share of an account balance leaves shortly after a key, alias, or metadata change</td><td>Escalate as possible account takeover</td></tr><tr><td>Privilege escalation</td><td>A high-risk permission or role is granted outside a change window</td><td>Alert operators and review the grant transaction</td></tr><tr><td>Rejection burst</td><td>One signer or client produces repeated rejected transactions</td><td>Check for credential abuse, integration errors, or probing</td></tr><tr><td>Automation change</td><td>A trigger, contract, or executor-related object changes unexpectedly</td><td>Pause dependent workflows until the change is reviewed</td></tr><tr><td>Governance-sensitive change</td><td>Peer, configuration, or runtime state changes occur without an approved ticket</td><td>Compare against the governance record and incident process</td></tr></tbody></table><p>Rules should be explicit about the evidence they require, the time window they evaluate, the action they take, and the person or system that can close the case. Thresholds that depend on customer risk, asset type, or jurisdiction belong in your monitoring service configuration, not in ad hoc scripts.</p><h2 id="response-controls" tabindex="-1">Response Controls <a class="header-anchor" href="#response-controls" aria-label="Permalink to &quot;Response Controls&quot;">​</a></h2><p>Design response actions before enabling alerts. A high-severity fraud case should have a documented path from detection to containment:</p><ul><li>notify the security, operations, and business owners responsible for the affected domain or asset definition</li><li>preserve the event cursor, block hash, transaction hash, authority, payload, and query snapshot used by the detection rule</li><li>pause application-side actions that are outside the ledger, such as checkout, withdrawal, signing, bridge, or settlement workflows</li><li>revoke roles or permissions that are no longer justified by the incident response plan</li><li>submit follow-up ledger transactions only when the active governance policy and permission model allow them</li><li>rotate keys when the evidence suggests signer compromise</li></ul><p>Avoid giving the monitoring service broad write access. Use a dedicated technical account with the smallest set of permissions required for the response actions it is allowed to perform. Human approval should remain part of any workflow that can move assets, change permissions, or alter validator-facing configuration.</p><h2 id="evidence-and-retention" tabindex="-1">Evidence and Retention <a class="header-anchor" href="#evidence-and-retention" aria-label="Permalink to &quot;Evidence and Retention&quot;">​</a></h2><p>Store monitoring evidence in an append-only system that is separate from the validator data directory. Each alert should include:</p><ul><li>event stream name and cursor</li><li>block height or block hash when available</li><li>transaction hash and authority</li><li>affected account, domain, asset, role, trigger, or configuration ID</li><li>raw event payload or a canonical hash of it</li><li>query snapshots used to enrich the alert</li><li>rule name, version, threshold, score, and reviewer decision</li></ul><p>Do not store sensitive investigation notes as public ledger metadata unless the network&#39;s data governance policy explicitly allows it. If you need to link an off-chain case to on-chain state, prefer a case identifier, signed attestation, or hash commitment that does not expose private details.</p><h2 id="implementation-checklist" tabindex="-1">Implementation Checklist <a class="header-anchor" href="#implementation-checklist" aria-label="Permalink to &quot;Implementation Checklist&quot;">​</a></h2><ul><li>Enable the telemetry profile needed for <code>/metrics</code> and operator routes.</li><li>Subscribe to Torii event streams with narrow filters for the objects you monitor.</li><li>Persist event cursors so the monitor can resume without gaps.</li><li>Reconcile streams with paginated queries on a regular schedule.</li><li>Keep risk thresholds and allow lists in version-controlled configuration.</li><li>Test alert rules against historical blocks before enabling automated actions.</li><li>Use dedicated technical accounts for response actions.</li><li>Review role and permission grants on a recurring schedule.</li><li>Include fraud-monitoring alerts in the incident response process.</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="/iroha-2-docs/blockchain/events.html">Events</a></li><li><a href="/iroha-2-docs/blockchain/filters.html">Filters</a></li><li><a href="/iroha-2-docs/blockchain/queries.html">Queries</a></li><li><a href="/iroha-2-docs/blockchain/permissions.html">Permissions</a></li><li><a href="/iroha-2-docs/guide/advanced/metrics.html">Performance and Metrics</a></li><li><a href="/iroha-2-docs/reference/torii-endpoints.html">Torii endpoints</a></li><li><a href="/iroha-2-docs/guide/security/operational-security.html">Operational Security</a></li></ul>',27)])])}const m=t(r,[["render",n]]);export{p as __pageData,m as default};
